__kernel void hotspot(const int iteration,
                      __global const float *power,
                      __global const float *temp_src,
                      __global float *temp_dst,
                      const int cols,
                      const int rows,
                      const int borderCols,
                      const int borderRows,
                      const float Cap,
                      const float Rx,
                      const float Ry,
                      const float Rz,
                      const float step)
{
    const int tx = get_local_id(0);
    const int ty = get_local_id(1);
    const int bx = get_group_id(0);
    const int by = get_group_id(1);

    const int small_block_cols = BLOCK_SIZE - (iteration * 2);
    const int small_block_rows = BLOCK_SIZE - (iteration * 2);

    const int x = bx * small_block_cols + tx - borderCols;
    const int y = by * small_block_rows + ty - borderRows;

    const int lidx = ty * BLOCK_SIZE + tx;

    __local float temp_local_0[BLOCK_SIZE * BLOCK_SIZE];
    __local float temp_local_1[BLOCK_SIZE * BLOCK_SIZE];
    __local float power_local[BLOCK_SIZE * BLOCK_SIZE];

    if (x >= 0 && x < cols && y >= 0 && y < rows) {
        const int gidx = y * cols + x;
        temp_local_0[lidx] = temp_src[gidx];
        power_local[lidx] = power[gidx];
    } else {
        temp_local_0[lidx] = 0.0f;
        power_local[lidx] = 0.0f;
    }

    barrier(CLK_LOCAL_MEM_FENCE);

    const float Rx_1 = 1.0f / Rx;
    const float Ry_1 = 1.0f / Ry;
    const float Rz_1 = 1.0f / Rz;
    const float Cap_1 = (step * 0.001f) / Cap; // match OpenMP source (step/1000 then /Cap)
    const float amb_temp = 80.0f;

    int src = 0;
    int dst = 1;

    for (int it = 0; it < iteration; ++it) {
        const int valid_compute =
            (tx >= (it + 1)) && (tx <= (BLOCK_SIZE - it - 2)) &&
            (ty >= (it + 1)) && (ty <= (BLOCK_SIZE - it - 2)) &&
            (x >= 0) && (x < cols) && (y >= 0) && (y < rows);

        if (valid_compute) {
            __local float *tin  = (src == 0) ? temp_local_0 : temp_local_1;
            __local float *tout = (dst == 0) ? temp_local_0 : temp_local_1;

            const float tc = tin[lidx];
            const float p  = power_local[lidx];
            float delta;

            if ((y == 0) && (x == 0)) {
                delta = Cap_1 * (p +
                                 (tin[lidx + 1] - tc) * Rx_1 +
                                 (tin[lidx + BLOCK_SIZE] - tc) * Ry_1 +
                                 (amb_temp - tc) * Rz_1);
            } else if ((y == 0) && (x == cols - 1)) {
                delta = Cap_1 * (p +
                                 (tin[lidx - 1] - tc) * Rx_1 +
                                 (tin[lidx + BLOCK_SIZE] - tc) * Ry_1 +
                                 (amb_temp - tc) * Rz_1);
            } else if ((y == rows - 1) && (x == cols - 1)) {
                delta = Cap_1 * (p +
                                 (tin[lidx - 1] - tc) * Rx_1 +
                                 (tin[lidx - BLOCK_SIZE] - tc) * Ry_1 +
                                 (amb_temp - tc) * Rz_1);
            } else if ((y == rows - 1) && (x == 0)) {
                delta = Cap_1 * (p +
                                 (tin[lidx + 1] - tc) * Rx_1 +
                                 (tin[lidx - BLOCK_SIZE] - tc) * Ry_1 +
                                 (amb_temp - tc) * Rz_1);
            } else if (y == 0) {
                delta = Cap_1 * (p +
                                 (tin[lidx + 1] + tin[lidx - 1] - 2.0f * tc) * Rx_1 +
                                 (tin[lidx + BLOCK_SIZE] - tc) * Ry_1 +
                                 (amb_temp - tc) * Rz_1);
            } else if (x == cols - 1) {
                delta = Cap_1 * (p +
                                 (tin[lidx + BLOCK_SIZE] + tin[lidx - BLOCK_SIZE] - 2.0f * tc) * Ry_1 +
                                 (tin[lidx - 1] - tc) * Rx_1 +
                                 (amb_temp - tc) * Rz_1);
            } else if (y == rows - 1) {
                delta = Cap_1 * (p +
                                 (tin[lidx + 1] + tin[lidx - 1] - 2.0f * tc) * Rx_1 +
                                 (tin[lidx - BLOCK_SIZE] - tc) * Ry_1 +
                                 (amb_temp - tc) * Rz_1);
            } else if (x == 0) {
                delta = Cap_1 * (p +
                                 (tin[lidx + BLOCK_SIZE] + tin[lidx - BLOCK_SIZE] - 2.0f * tc) * Ry_1 +
                                 (tin[lidx + 1] - tc) * Rx_1 +
                                 (amb_temp - tc) * Rz_1);
            } else {
                delta = Cap_1 * (p +
                                 (tin[lidx + BLOCK_SIZE] + tin[lidx - BLOCK_SIZE] - 2.0f * tc) * Ry_1 +
                                 (tin[lidx + 1] + tin[lidx - 1] - 2.0f * tc) * Rx_1 +
                                 (amb_temp - tc) * Rz_1);
            }

            tout[lidx] = tc + delta;
        }

        barrier(CLK_LOCAL_MEM_FENCE);
        src = 1 - src;
        dst = 1 - dst;
    }

    const int write_back =
        (tx >= borderCols) && (tx < (BLOCK_SIZE - borderCols)) &&
        (ty >= borderRows) && (ty < (BLOCK_SIZE - borderRows)) &&
        (x >= 0) && (x < cols) && (y >= 0) && (y < rows);

    if (write_back) {
        __local float *tfinal = (src == 0) ? temp_local_0 : temp_local_1;
        temp_dst[y * cols + x] = tfinal[lidx];
    }
}
